sys_script_include.script:
function AppBuilderImplementBusinessProcess(vApp,business_process)
{

/*

	TEST SCRIPT

	var strScope = 'x_snc_test_?';

	var grApp = x_snc_devtools.GetAppRecord(strScope);
	var grMetaData = new GlideRecord('sys_metadata');
	grMetaData.addQuery('sys_scope','=',grApp.sys_id);
	grMetaData.query();
	while(grMetaData.next())
	{
		gs.info(x_snc_devtools.RenderRecordSummary(grMetaData));
		x_snc_devtools.GlideRecordDelete(grMetaData);
	}

	var AppBuilderImplementBusinessProcess = x_snc_devtools.AppBuilderImplementBusinessProcess;
	AppBuilderImplementBusinessProcess(strScope,x_snc_devtools.BusinessProcessGetExample());

*/


	var grApp = GetAppRecord(vApp);

	if (IsValidRecord(grApp) == false)
	{
		LogError('AppBuilderImplementBusinessProcess: App could not be loaded.');
		return false;
	}

	if (grApp.scope == 'global')
	{
		LogError('AppBuilderImplementBusinessProcess: Global Apps are not supported.');
		return false;
	}

	var result = BusinessProcessValidate(business_process,true);

	if (result.valid == false)
	{
		LogError('AppBuilderImplementBusinessProcess: Business Process is invalid:\n' + RenderValue(result));
		return false;
	}

	var strParentTable = GetStringValue(GetValue(business_process,'parent_table'));
	if (strParentTable == '')
	{
		strParentTable = 'task';
	}
	var grParentTable = GetTableRecord(strParentTable);
	if (IsValidRecord(grParentTable) == false)
	{
		LogError('AppBuilderImplementBusinessProcess: Could not load parent table: ' + strParentTable);
		return false;
	}
	if (strParentTable != 'task' && IsDerivedFromTable(grParentTable,'task') == false)
	{
		LogError('AppBuilderImplementBusinessProcess: The parent table ("' + strParentTable + '") must be "task" or derived from "task"!');
		return false;
	}


	var strScope = GetStringValue(grApp.scope);
	var strScopeSysId = GetStringValue(grApp.sys_id);
	var strProcessId = GetStringValue(GetValue(business_process,'id'));
	var strProcessName = GetStringValue(GetValue(business_process,'name'));

	// ROLES

	var aRoles = GetValue(business_process,'_roles');

	var roleViewer = ArrayGetElementById(aRoles, 'viewer');
	if (IsObject(roleViewer) == false)
	{
		roleViewer = {
			id: 'viewer',
			description: 'A user that can view all data related to the process.'
			};
		aRoles.push(roleViewer);
	}

	var roleManager = ArrayGetElementById(aRoles, 'manager');
	if (IsObject(roleManager) == false)
	{
		roleManager = {
			id: 'manager',
			description: 'A user that can view and edit all data related to the process.'
			};
		aRoles.push(roleManager);
	}	

	var roleAdmin = ArrayGetElementById(aRoles, 'admin');
	if (IsObject(roleAdmin) == false)
	{
		roleAdmin = {
			id: 'admin',
			description: 'A user that can view, edit and delete all data related to the process.'
			};
		aRoles.push(roleAdmin);
	}

	for (var nRole = 0; nRole < aRoles.length; nRole++)
	{
		var role = aRoles[nRole];

		var strRoleSuffix = GetStringValue(GetValue(role,'id'));
		var strRoleName = strScope + '.' + strRoleSuffix;
		var strRoleDescription = GetStringValue(GetValue(role,'description'));

		var strRoleSysId = RecordInsertOrUpdate(
			'sys_user_role',
			{
				sys_scope: strScopeSysId,
				suffix: strRoleSuffix,
				name: strRoleName
			},
			{
			},
			{
				description: strRoleDescription
			});
		if (IsValidSysId(strRoleSysId) == false)
		{
			LogError('AppBuilderImplementBusinessProcess: Could not create/update role: ' + strRoleName);
			return false;
		}
		aRoles[nRole]['sys_id'] = strRoleSysId;
		aRoles[nRole]['name'] = strRoleName;
	}

	var roleAdmin = ArrayGetElementById(aRoles, 'admin');
	var roleManager = ArrayGetElementById(aRoles, 'manager');
	var roleViewer = ArrayGetElementById(aRoles, 'viewer');


	var strRoleContainsSysId = RecordInsertOrUpdate(
		'sys_user_role_contains',
		{
			sys_scope: strScopeSysId,
			role: roleAdmin.sys_id,
			contains: roleManager.sys_id
		},{},{});
	if (IsValidSysId(strRoleContainsSysId) == false)
	{
		LogError('AppBuilderImplementBusinessProcess: Could not add role manager to role admin.');
		return false;
	}

	for (var nRole = 0; nRole < aRoles.length; nRole++)
	{
		var role = aRoles[nRole];
		var strId = role['id'];
		if (strId != 'admin' && strId != 'viewer')
		{
			var strRoleContainsSysId = RecordInsertOrUpdate(
				'sys_user_role_contains',
				{
					sys_scope: strScopeSysId,
					role: role.sys_id,
					contains: roleViewer.sys_id
				},{},{});
			if (IsValidSysId(strRoleContainsSysId) == false)
			{
				LogError('AppBuilderImplementBusinessProcess: Could not add role viewer to role '+strId+'.');
				return false;
			}
		}
	}

	// TABLE

	var strTableName = strScope + '_' + strProcessId;
	var strTableLabel = strProcessName;


	var strTableSysId = RecordInsertOrUpdate(
		'sys_db_object',
		{
			sys_scope: strScopeSysId,
			name: strTableName
		},
		{
			super_class: grParentTable.sys_id
		},
		{
			label: strTableLabel,
			configuration_access: true,
			create_access: true,
			update_access: true,
			delete_access: true
		});

	if (IsValidSysId(strTableSysId) == false)
	{
		LogError('AppBuilderImplementBusinessProcess: Could not create/update table: ' + strTableName);
		return false;
	}


	// ACLs

	AppBuilderAclInsertOrUpdate(
		grApp,
		'record',
		'create',
		strTableName,
		'allow',
		'Allows users with process manager role create access to the table',
		[roleManager.name],
		null);		


	AppBuilderAclInsertOrUpdate(
		grApp,
		'record',
		'read',
		strTableName,
		'allow',
		'Allows users with process viewer role read access to the table',
		[roleViewer.name],
		null);

	AppBuilderAclInsertOrUpdate(
		grApp,
		'record',
		'write',
		strTableName,
		'allow',
		'Allows users with process manager role write access to the table',
		[roleManager.name],
		null);		

	AppBuilderAclInsertOrUpdate(
		grApp,
		'record',
		'delete',
		strTableName,
		'allow',
		'Allows users with process admin role delete access to the table',
		[roleAdmin.name],
		null);

	// STATES

	var aStates = GetValue(business_process,'_states');

	// Prepare Values (if not set)
	var bAllValuesSet = true;
	for (var nState = 0; nState < aStates.length; nState++)
	{
		var state = aStates[nState];
		var nStateValue = GetIntegerValue(GetValue(state,'value'));
		if (nStateValue == 0)
		{
			bAllValuesSet = false;
		}
	}

	if (bAllValuesSet == false)
	{
		for (var nState = 0; nState < aStates.length; nState++)
		{
			aStates[nState]['value'] = nState + 1;
		}
	}

	// Creating the Choice Set
	var strChoiceSetSysId = RecordInsertOrUpdate(
		'sys_choice_set',
		{
			sys_scope: strScopeSysId,
			table: strTableName,
			element: 'state'
		},
		{
		},
		{
		});
	if (IsValidSysId(strChoiceSetSysId) == false)
	{
		LogError('AppBuilderImplementBusinessProcess: Could not create/update Choice Set for: ' + strTableName + '.state');
		return false;
	}



	for (var nState = 0; nState < aStates.length; nState++)
	{
		var state = aStates[nState];
		var strStateName = GetStringValue(GetValue(state,'name'));
		var strStateDescription = GetStringValue(GetValue(state,'description'));
		var nStateValue = GetIntegerValue(GetValue(state,'value'));
		var strChoiceSysId = RecordInsertOrUpdate(
			'sys_choice',
			{
				name: strTableName,
				element: 'state',
				value: GetStringValue(nStateValue), // without GetStringValue it results in "1.0"
				language: 'en'
			},
			{
			},
			{
				hint: strStateDescription,
				label: strStateName,
				sequence: nState + 1
			});
		if (IsValidSysId(strChoiceSysId) == false)
		{
			LogError('AppBuilderImplementBusinessProcess: Could not create/update choice: ' + strStateName);
			return false;
		}
	}


	// FIELDS

	var strDictOverrideSysId = RecordInsertOrUpdate(
		'sys_dictionary_override',
		{
			sys_scope: strScopeSysId,
			base_table: 'task',
			name: strTableName,
			element: 'state'
		},
		{
		},
		{
			read_only_override: true,
			read_only: true
		});

	if (IsValidSysId(strDictOverrideSysId) == false)
	{
		LogError('AppBuilderImplementBusinessProcess: Could not create/update dictionary override for: ' + strTableName + '.state!');
		return false;
	}

	var strDictOverrideSysId = RecordInsertOrUpdate(
		'sys_dictionary_override',
		{
			sys_scope: strScopeSysId,
			base_table: 'task',
			name: strTableName,
			element: 'number'
		},
		{
		},
		{
			read_only_override: true,
			read_only: true
		});

	if (IsValidSysId(strDictOverrideSysId) == false)
	{
		LogError('AppBuilderImplementBusinessProcess: Could not create/update dictionary override for: ' + strTableName + '.number!');
		return false;
	}


	AppSanity(grApp);

	return true;
}
